@Override
public Action inspect(AtmosphereResource r) {
    AtmosphereResource.TRANSPORT transport = r.transport();
    switch(transport) {
        case WEBSOCKET:
        case SSE:
        case STREAMING:
            r.suspend();
            break;
        case LONG_POLLING:
            r.suspend(r.getAtmosphereConfig().getPropertyValue("polling.timeout", 5000L));
            break;
        default:
            break;
    }
    return Action.CONTINUE;
}

@Override
public Action inspect(AtmosphereResource r) {
    AtmosphereResource.TRANSPORT transport = r.transport();
    switch(transport) {
        case WEBSOCKET:
        case SSE:
        case STREAMING:
            // These transports require suspension
            r.suspend();
            break;
        case LONG_POLLING:
            // Long polling handled separately
            if (!r.getRequest().getHeader("Connection", "").equalsIgnoreCase("close")) {
                r.suspend();
            }
            break;
        default:
            // Other transports don't require suspension
            break;
    }
    return Action.CONTINUE;
}

